INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (898, 179485, 10, 98, '毕业の烦恼VS乐趣', '高三已经过去了，对于我的学习生涯来说，可能已经完成了60%，然而现在面对向往已久的大学生活，我竟然感到一丝的无奈。至于为什么，我自己也是问号。仔细的寻找原因，我想再没理由的一件事，总有它的源头。可能是我太想富有了吧，还是太想有自己的事业，我一心想开店，开公司，我多想尽早的忙碌，忙碌于自己的事业，但总是事与愿违，我还有N年的大学生活要过，可以就这样跳过这N年吗，有时候我甚至想心一狠，不读书了，但矛盾的心理立刻打败我。谁都知道读书好。我妈也老是在念叨―万般皆下品，惟有读书高。
<br>
<br>             有时候一个人在做某件事的时候，会灵魂出壳，思绪乱飞，总是幻想着今后的自己是如何的成功，如何的挥霍，如何的不需要爱情，如何的独自一人漫步在雾都午后的夕阳里，但当所有的美好骤然消失的时候，我才发现我依然还是穿着那条懒散的滑板裤。那种挫败感是形容不了的，更贴切的说是我根本不想去形容。我多想有一番作为啊，可我现在能做的事只有每天消磨那无聊的时光然后等待开学时的一点新鲜感。
<br>
<br>                不知道你是否看过一个女孩平静地在电脑前上网，然后突然做出了与其有极大不同的动作，such as,站起来跺脚，或着像死了一样地躺在地上，你可能觉得她是不是神经线接错或灵魂失禁，但我却常做这种事，以至于我妈很有想拉我去精神病院的冲动，因为我妈知道她的女儿不可能是因为书读太多而头脑发热，哎，可是她却不知道原来我也有那么烦恼的时候，她以为她经常认为我没脑袋我就都从不考虑事情，她是不会知道我现在正有那么一点飘摇的烦恼，她更不会明白一只溺水的狮子会有多么难受。罢了，我想。
<br>
<br>                我每天都去春水堂报道，每当每次准时在同一个地点出现的时候，我总要从内心最深处发出这样的感叹：要是我在学校的时候能那么准时不知该多好，也不会因为迟到而出了点名，让认识我的人都知道，要和我约在中山路见面最好是比原来的时间晚到30分钟，原来啊，出名就这样不好。又是我们4个无聊的可爱少女，“打牌打牌！”一声令下，我们各自归位，开始杀了起来，待到对方偃旗息鼓，便是我们春风得意的时候。在“战场”上我们是如此专注，可以不顾身边有没有超级大帅哥走过，虽然偶尔会不小心去瞄一眼，但战况激烈，无暇多看。虽然我们是可爱の少女，但也有没有形象的时候，我们穿拖鞋去打牌，然后放肆的把脚丫跨在椅子上，呐喊穿水手服的服务生为美女，激动时大声叫，用力拍桌子，（有一次就因为这样打碎了杯子而心痛的掏出36块钱交给美女）偷偷告诉你哦，有时候三字经会不小心从我们的口中跑出来，不过，那是无心的，嘿嘿。打牌并也不是那么神奇的事情，但却让我觉得有种豁然开朗的感觉，我不想刻意去雕塑自己，不喜欢坐着的时候要把双手放在腿上，不喜欢笑的时候要用手遮住，不喜欢轻声细语，总之，不喜欢做淑女。因为我们还年轻，我们要的是快乐，我们要享受的是自由，要做什么就做什么，（不用花太多钱就可以做到的事）想去哪里就去哪里。（厦门岛内）打完牌后大概是11点吧，这个时候对于我们这些夜猫子来说才是一天的开始，如果感到肚子扁扁的时候，我们大概会一群人疯去湖滨4里一边吃肉串，一边狂喝菊花茶，说说笑笑，不过说真的那里是不是汇聚了厦门市所有的乞丐，一个乞讨完又来一个，而且没有重复过，这还不是十分头疼，最让人受不了的是那些买花的小女孩，不鸟她吧，她又死赖着，不过还好，这样的女孩都是为着男生转的，她们总是对我身边的男生说：“买朵花送给姐姐吧，姐姐那么漂亮。”一开始听到漂亮这两个字眼，心里还蛮高兴的，于是看买花女孩爽就给了她几串肉串，但在几秒种过后，熟悉的声音环绕在耳边，回头一看买花女孩，她……她……她……竟然能对一个重量级的老女人说同样的话，原来兴致勃勃吃在口中的豆腐一下子比局口街里卖的臭豆腐还恶心。于是再有买花女孩来说同样的话，我就觉得脑浆要崩裂开，胸中燃起了熊熊烈火。因为她给我留下了阴影，挥之不去，另我很有扁她的欲望，但又一想，她大概会拿着未成年人保护法这块“免死金牌”把我告上法院，那我不是很吃亏，经过迅速的思想斗争后，我决定放了她。虽然这里又热又熏，但做为一个兢兢业业的现在人来说，吃肉串还是需要氛围的，那样才会有激情，令人食欲大开。于是我们点它几百串肉串，玉米，排骨，鸡翅，豆腐，香肠……总之只要是能烤的我们都能吃，吃烧烤，或许是我们对过去的人最好的缅怀方式，而且我还十分虔诚，我们能一直吃，一直吃，吃到大家都打着幸福的饱嗝时，我们才会一边嚼着口中还没吞下去的食物，一边擦着那五味具全的嘴，手一挥，打的回家去了。这是我们的情况一。，
<br>
<br>             情况二，还是打完牌，大家还精力旺盛，于是拨动手中的电话，招集了一群人马，5个人就去小包厢，6-10就去中包厢，10个以上就去大包厢，这是我们的原则。人马招集好了后便轰轰烈烈的杀到里这20米之遥的海派自助式KTV唱歌去。春水堂是我们第一常去的地方，而海派则是第二，一个星期起码也报到3次。因此，对我们来说是十分熟悉，正如有些人说的，走海派比走你家的厨房还顺走。一进包厢，无论是大包厢，中包厢，还是小包厢，我们都十分自觉的把包包都放在沙发的最一边。然后心情激动的开始今天的第一首歌――“浪花一朵朵”。这首歌是我们的热身曲，唱着首歌的时候，我们需要比划动作。“我要你陪着我，看那海龟水中游，慢慢地爬在沙滩上，数着浪花一朵朵。”啊！我们的动作是如此默契，我们的笑声是如此的真诚，这就是没有杂质的友谊，至少现在是。欢歌笑语，是不是过节了，晕，还没有呢。我们的歌声和我们的笑声融会贯通在整个包厢里活蹦乱跳，形成了只有天堂才听得见的乐章，说白点，我的意思是告诉你，我们就是人间天堂。“咔嚓”要是有人把包厢里的灯源关掉，只剩电视机里闪烁的七色光时，就是我们即将开始的CRAZY TIME，大家情绪高昂，整个人蠢蠢欲动，全声上下的血液在沸腾，每个细胞都在抖动，快按奈不住要释放的热情。把音量开到震耳欲聋的极限，当郑秀文的独一无二+眉飞色舞（虽然觉得李贞贤的声音比较有说服力，但包厢里的确没有）轰炸过来的时候，早已经站在沙发上的大家一触即发，疯狂起来了，随着强烈的节奏感袭来令我们不断舞动着身躯，狂叫，大家手扶着墙壁，用尽全身的力气拼命摇头，而我却更加买力，因为只有当汗水滑落时才会有成就感，我想，大家都CRAZY了。这就是我们要的HIGHT的感觉。灯光在闪烁，心快图腾，真好，这样的感觉和一点点醉的感觉一样，什么都可以不想，什么都可以不在乎，什么都可以看得很开。两首歌结束后，大家都瘫倒在沙发上，喘着粗气，红光满面，汗流浃背，流汗比下雨还夸张。大家你看看我，我看看你，虽然我不知道大家笑的内容是什么，但大家却一直笑，或许是为了这真诚的友谊，或许是为没被人赶出海派而暗自高兴，更或许是莫名的吧。接下来一曲抒情的音乐，恢复了我们回家的体力，曲终人散，虽然这4个字看起来有点哀伤，可对我们来说，有散才有聚，因为我们都相信我们的心是在一起的。
<br>
<br>               坐在归途的的士车上，我想：我是不是荒废我了我青春？不过这个念头一晃而过，没留下痕迹，我们都还年轻，我们现在能挥霍的不是金钱，而是我们的青春。我不要做个被束缚的人，我想放纵，我要放纵。虽然那些乱七八糟的道理我都懂，但此刻我并不想去理会。
<br>
<br>           现在已经是凌晨5点了，在凌晨4点的时候我早已写好了以上的文字，却因为自己阅读时修改而不小心删除了一半以上，结果我又花了1个小时的时间写到这里，我想，为了我们的友谊，再花一个小时是值得的。突然觉得该是听首歌的时候了，我选择了“美丽心情”这首歌，因为我希望我怀着美丽的心情睡去，一曲终了，也该睡了。我想，天下没有不散的筵席，不久后我就要开始读书，不久后我的朋友都要去工作了，不久后大家都回到各自的轨道上去，这样的生活也该结束了，整个夏日的愉快都是我最好的回忆。累了，睡吧。', '高三已经过去了，对于我的学习生涯来说，可能已经完成了60%，然而现在面对向往已久的大学生活，我竟然感到一丝的无奈。至于为什么，我自己也是问号。仔细的寻找原因，我想再没理由的一件事，总有它的源头。可能是我太想富有了吧，还是太想有自己的事业，我一心想开店，开公司，我多想尽早的忙碌，忙碌于自己的事业，但总是事与愿违，我还有N年的大学生活要过，可以就这样跳过这N年吗，有时候我甚至想心一狠，不读书了，但矛盾的心理立刻打败我。谁都知道读书好。我妈也老是在念叨―万般皆下品，惟有读书高。

有时候一个人在做某件事的时候，会灵魂出壳，思绪乱飞，总是幻想着今后的自己是如何的成功，如何的挥霍，如何的不需要爱情，如何的独自一人漫步在雾都午后的夕阳里，但当所有的美好骤然消失的时候，我才发现我依然还是穿着那条懒散的滑板裤。那种挫败感是形容不了的，更贴切的说是我根本不想去形容。我多想有一番作为啊，可我现在能做的事只有每天消磨那无聊的时光然后等待开学时的一点新鲜感。

不知道你是否看过一个女孩平静地在电脑前上网，然后突然做出了与其有极大不同的动作，such as,站起来跺脚，或着像死了一样地躺在地上，你可能觉得她是不是神经线接错或灵魂失禁，但我却常做这种事，以至于我妈很有想拉我去精神病院的冲动，因为我妈知道她的女儿不可能是因为书读太多而头脑发热，哎，可是她却不知道原来我也有那么烦恼的时候，她以为她经常认为我没脑袋我就都从不考虑事情，她是不会知道我现在正有那么一点飘摇的烦恼，她更不会明白一只溺水的狮子会有多么难受。罢了，我想。

